// Extraer texto del response Claude + log estructurado
const response = $input.item.json;
const saludo = response.content?.[0]?.text || 'Saludo no disponible';
const traceId = `test-50-${Date.now()}-${Math.random().toString(36).substr(2, 8)}`;

// Log estructurado
console.log(JSON.stringify({
  level: 'INFO',
  event: 'saludo_generado_ok',
  trace_id: traceId,
  timestamp: new Date().toISOString(),
  input_usage: response.usage,
  length: saludo.length
}));

return {
  json: {
    saludo: saludo,
    trace_id: traceId,
    status: 'success',
    model: response.model,
    tokens_used: response.usage?.output_tokens || 0
  }
};

// Self-healing fallback: Anthropic API fallo tras 3 retries
const traceId = `test-50-fb-${Date.now()}-${Math.random().toString(36).substr(2, 8)}`;
const nombre = $('Webhook Saludo').item.json.body?.nombre || $('Webhook Saludo').item.json.nombre || 'amigo';

// Log estructurado de fallo + fallback activado
console.log(JSON.stringify({
  level: 'WARNING',
  event: 'anthropic_api_fallback_activated',
  trace_id: traceId,
  timestamp: new Date().toISOString(),
  reason: 'anthropic_api_3_retries_failed',
  fallback_used: 'static_message'
}));

return {
  json: {
    saludo: `Hola ${nombre}, el servicio de saludos esta temporalmente no disponible. Intentalo de nuevo en unos minutos.`,
    trace_id: traceId,
    status: 'fallback',
    model: 'fallback-static',
    tokens_used: 0
  }
};
